document.addEventListener("DOMContentLoaded", function () {
    
    // ==========================================
    // INTERSECTION OBSERVER ENTRANCE SETUP
    // ==========================================
    const sections = document.querySelectorAll("section");
    const revealOptions = {
        threshold: 0.10,
        rootMargin: "0px 0px -40px 0px"
    };

    const sectionObserver = new IntersectionObserver(function (entries, observer) {
        entries.forEach(entry => {
            if (entry.isIntersecting) {
                entry.target.classList.add("reveal-active");
                if (entry.target.id === "skills") {
                    animateProgressBars();
                }
            }
        });
    }, revealOptions);

    sections.forEach(section => {
        section.classList.add("reveal");
        sectionObserver.observe(section);
    });

    function animateProgressBars() {
        const progressBars = document.querySelectorAll(".skill-progress-bar");
        progressBars.forEach(bar => {
            const targetWidth = bar.getAttribute("data-target-width");
            if (targetWidth) {
                bar.style.width = targetWidth;
            }
        });
    }

    const navLinks = document.querySelectorAll("nav .nav-links a");

    window.addEventListener("scroll", function () {
        let activeSectionId = "";
        sections.forEach(section => {
            if (window.scrollY >= section.offsetTop - 240) {
                activeSectionId = section.getAttribute("id");
            }
        });
        navLinks.forEach(link => {
            link.classList.remove("active");
            if (link.getAttribute("href") === "#" + activeSectionId) {
                link.classList.add("active");
            }
        });
    });

    const contactForm = document.getElementById("portfolioContactForm");
    if (contactForm) {
        contactForm.addEventListener("submit", function (event) {
            event.preventDefault();
            alert("Thank you for contacting me!");
            contactForm.reset();
        });
    }

    // ==========================================
    // PROJECT IMAGE MODAL VIEWER
    // ==========================================
    const projectImages = {
        "bjj": [
            { src: "Image/BJJ1.JPG", caption: "BJJ - Competition" },
            { src: "Image/BJJ3.JPG", caption: "BJJ - Training" },
            { src: "Image/BJJ5.JPG", caption: "BJJ - Competition" }
        ],
        "mediaops": [
            { src: "Image/SOCCOM1.jpg", caption: "Media Ops - Event 1" },
            { src: "Image/SOCCOM2.jpg", caption: "Media Ops - Event 2" },
            { src: "Image/SOCCOM3.png", caption: "Media Ops - Event 3" },
            { src: "Image/SOCOOM4.png", caption: "Media Ops - Event 4" }
        ],
        "spincycle": [
            { src: "data:image/png;base64,", caption: "SpinCycle — Home Dashboard" },
            { src: "data:image/png;base64,", caption: "SpinCycle — Job Order Dashboard" }
        ],
        "lexical": [
            { src: "Image/DSArv.jpg", caption: "Syntax Analyzer" },
            { src: "data:image/jpeg;base64,", caption: "Lexical Analyzer — Token Visualization" }
        ],
        "dsarv": [
            { src: "data:image/jpeg;base64,", caption: "DSArv — Lexical & Syntax Analyzer UI" }
        ]
    };

    const modal = document.createElement("div");
    modal.id = "projectModal";
    modal.innerHTML = `
        <div class="modal-backdrop"></div>
        <div class="modal-panel">
            <button class="modal-close" aria-label="Close">&times;</button>
            <div class="modal-header">
                <h3 class="modal-title"></h3>
            </div>
            <div class="modal-image-area">
                <button class="modal-nav modal-prev" aria-label="Previous">&#8592;</button>
                <div class="modal-img-wrapper">
                    <img class="modal-img" src="" alt="" />
                    <p class="modal-caption"></p>
                </div>
                <button class="modal-nav modal-next" aria-label="Next">&#8594;</button>
            </div>
            <div class="modal-dots"></div>
        </div>
    `;
    document.body.appendChild(modal);

    let currentImages = [];
    let currentIndex = 0;

    function openModal(projectKey, title) {
        currentImages = projectImages[projectKey] || [];
        currentIndex = 0;
        if (!currentImages.length) return;
        document.querySelector(".modal-title").textContent = title;
        renderModalSlide();
        modal.classList.add("modal-open");
        document.body.style.overflow = "hidden";
    }

    function renderModalSlide() {
        const img = modal.querySelector(".modal-img");
        const caption = modal.querySelector(".modal-caption");
        const dots = modal.querySelector(".modal-dots");
        const prev = modal.querySelector(".modal-prev");
        const next = modal.querySelector(".modal-next");

        img.src = currentImages[currentIndex].src;
        img.alt = currentImages[currentIndex].caption;
        caption.textContent = currentImages[currentIndex].caption;

        dots.innerHTML = currentImages.map((_, i) =>
            '<span class="modal-dot ' + (i === currentIndex ? 'active' : '') + '" data-index="' + i + '"></span>'
        ).join("");

        dots.querySelectorAll(".modal-dot").forEach(dot => {
            dot.addEventListener("click", () => {
                currentIndex = parseInt(dot.dataset.index);
                renderModalSlide();
            });
        });

        prev.style.display = currentImages.length > 1 ? "flex" : "none";
        next.style.display = currentImages.length > 1 ? "flex" : "none";
    }

    function closeModal() {
        modal.classList.remove("modal-open");
        document.body.style.overflow = "";
    }

    modal.querySelector(".modal-close").addEventListener("click", closeModal);
    modal.querySelector(".modal-backdrop").addEventListener("click", closeModal);
    modal.querySelector(".modal-prev").addEventListener("click", () => {
        currentIndex = (currentIndex - 1 + currentImages.length) % currentImages.length;
        renderModalSlide();
    });
    modal.querySelector(".modal-next").addEventListener("click", () => {
        currentIndex = (currentIndex + 1) % currentImages.length;
        renderModalSlide();
    });

    document.addEventListener("keydown", (e) => {
        if (!modal.classList.contains("modal-open")) return;
        if (e.key === "Escape") closeModal();
        if (e.key === "ArrowLeft") { currentIndex = (currentIndex - 1 + currentImages.length) % currentImages.length; renderModalSlide(); }
        if (e.key === "ArrowRight") { currentIndex = (currentIndex + 1) % currentImages.length; renderModalSlide(); }
    });

    document.querySelectorAll(".gallery-view-btn").forEach(btn => {
        btn.addEventListener("click", () => {
            openModal(btn.dataset.project, btn.dataset.title);
        });
    });
});